import Card from '@mui/material/Card';
import CardContent from '@mui/material/CardContent';
import Typography from '@mui/material/Typography';
import Grid from '@mui/material/Grid';
import Stack from '@mui/material/Stack';
import IconButton from '@mui/material/IconButton';
import DoneIcon from '@mui/icons-material/Done';
import EditIcon from '@mui/icons-material/Edit';
import { useContext, useState } from "react"
import AlertDialog from "./AlertDialog.jsx"
import { tasksContext } from '../Context/tasksContext.js'
import Button from '@mui/material/Button';
import TextField from '@mui/material/TextField';
import Dialog from '@mui/material/Dialog';
import DialogActions from '@mui/material/DialogActions';
import DialogContent from '@mui/material/DialogContent';
import DialogTitle from '@mui/material/DialogTitle';
export default function ToDo({id}) {
    let useTaskContext = useContext(tasksContext)
    let [showDialog, setShowDialog] = useState(false);
    //Function Open And Close
    function handleClose() {
        setShowDialog(false);
    }
    function handleOpen() {
        setShowDialog(true)
    }
    //End
    let newTodo = useTaskContext.todos.find((todo) => {
        return todo.id === id;
    })
    //handle Submit
    function handleSubmit(e) {
        e.preventDefault();
        let newTodoTasks = [...useTaskContext.todos]
        let todosTasks = newTodoTasks.map((todo)=>{
            if (newTodo.id===todo.id){
                todo.title = titleValue;
                todo.details = detailsValue;
            }
            return todo
        })
        useTaskContext.setTodos(todosTasks)
        localStorage.setItem("todos",JSON.stringify(todosTasks))
        handleClose()
    }
    let [titleValue, setTitleValue] = useState(newTodo.title)
    let [detailsValue, setDetailsValue] = useState(newTodo.details)
    function handleEditTask() {
        let newTask = [...useTaskContext.todos];
        let tasks = newTask.map((task) => {
            if (id === task.id) {
                task.isCompleted = !task.isCompleted;
            }
            return task;
        });
        useTaskContext.setTodos(tasks);
        localStorage.setItem("todos",JSON.stringify(tasks))
    }
    return (
        <>
            <Dialog open={showDialog} onClose={handleClose} style={{direction:"rtl"}}>
                <DialogTitle style={{ fontFamily: "Alexandria", fontWeight: "600" }}>تعديل المهمة{`(${newTodo.title})`}</DialogTitle>
                <DialogContent>
                    <form onSubmit={(e) => handleSubmit(e)} id="subscription-form">
                        <TextField
                            autoFocus
                            required
                            margin="dense"
                            id="title"
                            name="title"
                            label="العنوان"
                            type="text"
                            fullWidth
                            variant="standard"
                            value={titleValue}
                            onChange={(e) => setTitleValue(e.target.value)}
                            style={{ fontFamily: "Alexandria", fontWeight: "400" }}
                        />
                        <TextField
                            autoFocus
                            required
                            margin="dense"
                            id="details"
                            name="details"
                            label="التفاصيل"
                            type="text"
                            fullWidth
                            variant="standard"
                            value={detailsValue}
                            onChange={(e) => setDetailsValue(e.target.value)}
                            style={{ fontFamily: "Alexandria", fontWeight: "400" }}
                        />
                    </form>
                </DialogContent>
                <DialogActions>
                    <Button onClick={handleClose} style={{color:"rgba(190, 13, 161, 0.97)",fontFamily: "Alexandria", fontWeight: "400" }}>الألغاء</Button>
                    <Button style={{ fontFamily: "Alexandria", fontWeight: "400",color:"rgba(190, 13, 161, 0.97)"}} type="submit" form="subscription-form">
                        تعديل
                    </Button>
                </DialogActions>
            </Dialog>
            <Card className='card-height' sx={{ minWidth: 275 }} style={{ textAlign: "center", marginTop: "20px", backgroundColor: "#283593" }}>
                <CardContent>
                    <Grid container spacing={2} style={{ alignItems: "center" }}>
                        <Grid size={4}>
                            <Stack direction="row" spacing={2}>
                                <AlertDialog id={newTodo.id} />
                                <IconButton color="secondary" aria-label="add an alarm" style={{ backgroundColor: newTodo.isCompleted ? "rgba(55, 214, 23, 0.97)" : "rgba(245, 248, 245, 0.97)" }} onClick={() => {
                                    handleEditTask()
                                }}>
                                    <DoneIcon style={{ color: newTodo.isCompleted ? "white" : "rgba(55, 214, 23, 0.97)" }} />
                                </IconButton>
                                <IconButton color="primary" aria-label="add to shopping cart" style={{ backgroundColor: "rgba(252, 252, 252, 0.97)" }} onClick={handleOpen}>
                                    <EditIcon />
                                </IconButton>
                            </Stack>
                        </Grid>
                        <Grid size={8} style={{ textAlign: "right" }}>
                            <Typography style={{ color: "white", fontFamily: "Alexandria", fontWeight: "400",textDecoration: newTodo.isCompleted?"line-through":"none"}} variant="h5" component="p" sx={{ color: 'text.primary' }}>
                                {newTodo.title}
                            </Typography>
                            <Typography style={{ fontWeigth: "normal", color: "rgba(215, 221, 221, 0.7)", marginTop: "10px", fontFamily: "Alexandria", fontWeight: "400" }} component="p" sx={{ color: 'text.primary' }}>
                                {newTodo.details}
                            </Typography>
                        </Grid>
                    </Grid>

                </CardContent>
            </Card>
        </>
    )
}