import * as React from 'react';
import Button from '@mui/material/Button';
import Dialog from '@mui/material/Dialog';
import DialogActions from '@mui/material/DialogActions';
import DialogContent from '@mui/material/DialogContent';
import DialogContentText from '@mui/material/DialogContentText';
import DialogTitle from '@mui/material/DialogTitle';
import IconButton from '@mui/material/IconButton';
import DeleteOutlinedIcon from '@mui/icons-material/DeleteOutlined';
import { useContext } from "react"
import { tasksContext } from '../Context/tasksContext.js'


export default function AlertDialog({id}) {
  let useTaskContext = useContext(tasksContext)
  const [open, setOpen] = React.useState(false);

  const handleClickOpen = () => {
    setOpen(true);
  };

  const handleClose = () => {
    setOpen(false);
  };
  function handleDeleteTask() {
    let newTask = [...useTaskContext.todos];
    let tasks = newTask.filter((task) => {
      return id !== task.id
    })
    useTaskContext.setTodos(tasks);
    localStorage.setItem("todos",JSON.stringify(tasks))
    handleClose()
  }
  return (
    <React.Fragment>
      <IconButton aria-label="delete" style={{ backgroundColor: "rgba(252, 252, 252, 0.97)", border: "1px solid red" }} onClick={handleClickOpen}>
        <DeleteOutlinedIcon style={{ color: "red"}} />
      </IconButton>
      <Dialog
        open={open}
        onClose={handleClose}
        aria-labelledby="alert-dialog-title"
        aria-describedby="alert-dialog-description"
        role="alertdialog"
        style={{direction:"rtl"}}
      >
        <DialogTitle id="alert-dialog-title" style={{color:"rgb(26, 25, 25)",fontFamily:"Alexandria",fontWeight: "600"}}>
          {"هل أنت متأكد من رغبتك في حذف المهمة؟"}
        </DialogTitle>
        <DialogContent>
          <DialogContentText style={{color:"rgb(26, 25, 25)",fontFamily:"Alexandria",fontWeight: "400"}} id="alert-dialog-description">
            لايمكنك التراجع عن الحذف في حال اختيارك (الحذف)
          </DialogContentText>
        </DialogContent>
        <DialogActions>
          <Button onClick={handleClose} autoFocus style={{color:"red",fontFamily:"Alexandria",fontWeight: "400"}}>
           الألغاء
          </Button>
          <Button onClick={handleDeleteTask} style={{color:"red",fontFamily:"Alexandria",fontWeight: "400"}}>تأكيد</Button>
        </DialogActions>
      </Dialog>
    </React.Fragment>
  );
}