//Components
import Container from "@mui/material/Container";
import Card from "@mui/material/Card";
import Box from "@mui/material/Box";
import CardContent from "@mui/material/CardContent";
import Button from "@mui/material/Button";
import Grid from "@mui/material/Grid";
import TextField from "@mui/material/TextField";
import Typography from "@mui/material/Typography";
import Divider from "@mui/material/Divider";
import AssignmentIcon from "@mui/icons-material/Assignment";
import ToggleButton from "@mui/material/ToggleButton";
import * as React from "react";
import ToDo from "./ToDo.jsx";
import ToggleButtonGroup from "@mui/material/ToggleButtonGroup";
import { useState, useEffect } from "react";
import { useContext } from "react"
import { tasksContext } from '../Context/tasksContext.js'
//Others
import { v4 as uuidv4 } from "uuid";
export default function ToDoList() {
  let [valueField, setValueField] = useState("");
  let [displayedTodoTyped,setDisplayedTodoTyped] = useState("all");
  let useTaskContext = useContext(tasksContext)
  let newTodo = [...useTaskContext.todos];


  useEffect(() => {
    useTaskContext.setTodos(JSON.parse(localStorage.getItem("todos")))
    // console.log("Calling UseEffect")
  }, [])


    //fillteration array
  const completedTodos = newTodo.filter((todo) => {
    return todo.isCompleted;
  })
  //fillteration array
  const notcompletedTodos = newTodo.filter((todo) => {
    return !todo.isCompleted;
  })

  let todosToBeRendered = newTodo;
  if(displayedTodoTyped==="completed"){
      todosToBeRendered = completedTodos;
  }
  else if(displayedTodoTyped==="non-completed"){
    todosToBeRendered = notcompletedTodos;
  }
  
  //All Todos
  const todosJSX = todosToBeRendered.map((todo) => {
    return (
      <ToDo
        key={todo.id}
        id={todo.id}
      />
    );
  });
  function handleAddTask() {
    let newAddTask = [...useTaskContext.todos, {
      id: uuidv4(),
      title: valueField,
      details: "",
      isCompleted: false
    }];
    useTaskContext.setTodos(newAddTask);
    localStorage.setItem("todos", JSON.stringify(newAddTask))
    setValueField("");
  }
  return (
    <Container maxWidth="sm">
      <Card sx={{ minWidth: 275 }} style={{ textAlign: "center" }}>
        <CardContent>
          <Typography
            style={{ fontFamily: "Alexandria", fontWeight: "bold" }}
            variant="h2"
            component="h2"
            sx={{ color: "text.primary" }}
          >
            مهامي
          </Typography>
          <Divider>
            <AssignmentIcon style={{ color: "rgb(31, 107, 206)" }} />
          </Divider>
          <ToggleButtonGroup
            value={displayedTodoTyped}
            exclusive
            aria-label="text alignment"
          >
            <ToggleButton
              style={{ fontFamily: "Alexandria", fontWeight: "600" }}
              value="non-completed"
              aria-label="left aligned"
              onClick={()=>setDisplayedTodoTyped("non-completed")}
            >
              غير منجز
            </ToggleButton>
            <ToggleButton
              style={{ fontFamily: "Alexandria", fontWeight: "600" }}
              value="completed"
              aria-label="centered"
              onClick={()=>setDisplayedTodoTyped("completed")}
            >
              منجز
            </ToggleButton>
            <ToggleButton
              style={{ fontFamily: "Alexandria", fontWeight: "600" }}
              value="all"
              aria-label="right aligned"
              onClick={()=>setDisplayedTodoTyped('all')}
            >
              الكل
            </ToggleButton>
          </ToggleButtonGroup>
          <Box style={{overflow:"scroll",maxHeight:"300px",marginTop:"30px"}}>
            {todosJSX}
          </Box>
          
          <Grid
            container
            spacing={2}
            style={{ alignItems: "center", marginTop: "30px"}}
          >
            <Grid size={4}>
              <Button
                onClick={handleAddTask}
                variant="contained"
                disabled={valueField.trim()==""}
                style={{
                  fontFamily: "Alexandria",
                  fontWeight: "400",
                  width: "100%",
                  height: "56px",
                  backgroundColor: "rgba(190, 13, 161, 0.97)",
                }}
              >
                إضافة
              </Button>
            </Grid>
            <Grid size={8}>
              <TextField
                value={valueField}
                onChange={(event) => setValueField(event.target.value)}
                style={{
                  fontFamily: "Alexandria",
                  fontWeight: "400",
                  width: "100%",
                }}
                id="outlined-basic"
                label="عنوان المهمة"
                variant="outlined"
              />
            </Grid>
          </Grid>
        </CardContent>
      </Card>
    </Container>
  );
}
